class MKAverage {
    int m, k;
    TreeSet<Integer> set;
    List<Integer> list;
    long sum;

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        set = new TreeSet<>();
        list = new ArrayList<>();
    }

    public void addElement(int num) {
        list.add(num);
        set.add(num);
        sum += num;
        if (list.size() > m) {
            sum -= list.get(0);
            set.remove(list.get(0));
            list.remove(0);
        }
    }

    public int calculateMKAverage() {
        if (list.size() < m) return -1;
        int cnt = m - k * 2;
        int avg = 0;
        Iterator<Integer> it = set.iterator();
        for (int i = 0; i < k; i++) it.next();
        for (int i = 0; i < cnt; i++) {
            avg += it.next();
        }
        return avg / cnt;
    }
}
```
